COMMENT ON COLUMN "public"."check_in_streak_grant_reward_item"."asset_type" IS E'奖励资产类型（1=积分；2=经验）。';
COMMENT ON COLUMN "public"."check_in_streak_grant_reward_item"."asset_key" IS E'奖励资产键。';
