COMMENT ON COLUMN "public"."membership_auto_renew_agreement"."environment" IS E'运行环境（1=沙箱；2=正式）。';
COMMENT ON COLUMN "public"."membership_auto_renew_agreement"."client_app_key" IS E'客户端应用键，同一部署内区分多应用。';
COMMENT ON COLUMN "public"."membership_auto_renew_agreement"."provider_config_id" IS E'支付 provider 配置 ID。';
COMMENT ON COLUMN "public"."membership_auto_renew_agreement"."provider_config_version" IS E'签约时 provider 配置版本快照。';
COMMENT ON COLUMN "public"."membership_auto_renew_agreement"."credential_version_ref" IS E'签约时密钥版本引用快照。';
COMMENT ON COLUMN "public"."membership_auto_renew_agreement"."agreement_no" IS E'第三方签约协议号。';
COMMENT ON COLUMN "public"."membership_auto_renew_agreement"."status" IS E'协议状态（1=有效；2=已取消；3=已过期；4=签约失败）。';
COMMENT ON COLUMN "public"."membership_auto_renew_agreement"."signed_at" IS E'签约成功时间。';
COMMENT ON COLUMN "public"."membership_auto_renew_agreement"."next_renew_at" IS E'下次预计续扣时间。';
COMMENT ON COLUMN "public"."membership_auto_renew_agreement"."cancelled_at" IS E'取消时间。';
COMMENT ON COLUMN "public"."membership_auto_renew_agreement"."raw_payload" IS E'原始 provider payload。';
COMMENT ON COLUMN "public"."membership_auto_renew_agreement"."agreement_snapshot" IS E'签约配置与套餐快照，不包含明文密钥。';
COMMENT ON COLUMN "public"."membership_auto_renew_agreement"."created_at" IS E'创建时间。';
COMMENT ON COLUMN "public"."membership_auto_renew_agreement"."updated_at" IS E'更新时间。';
COMMENT ON TABLE "public"."membership_benefit_claim_record" IS E'会员权益领取记录表。\n每日礼包和手动领取权益通过 bizKey 保证幂等，已发放事实不因权益下架而删除。';
